package com.securestack.analysis.rules;import org.springframework.stereotype.Component;import java.util.*;import java.util.regex.*;import com.securestack.analysis.SecurityRule;import com.securestack.dto.Dto.ScanFileInput;import com.securestack.model.Entities.Finding;import com.securestack.model.Enums.*;import com.securestack.util.Sanitizer;
abstract class BaseRule implements SecurityRule{Finding f(ScanFileInput file,String title,Severity sev,Category cat,Confidence conf,String ev,String rec){Finding x=new Finding();x.fileName=file.fileName();x.lineNumber=line(file.content(),ev);x.title=title;x.description=title+" detected by SecureStack AI static analysis.";x.severity=sev;x.category=cat;x.confidence=conf;x.evidence=Sanitizer.mask(ev);x.recommendation=rec;x.secureExample="Use environment variables, allowlists, parameterized APIs, and least-privilege configuration.";x.ruleId=id();return x;}int line(String c,String ev){String[]ls=c.split("\\R",-1);for(int i=0;i<ls.length;i++)if(ls[i].contains(ev.trim())||ev.contains(ls[i].trim()))return i+1;return 1;}boolean any(ScanFileInput f,String...ext){String n=f.fileName().toLowerCase();for(String e:ext)if(n.endsWith(e)||n.equals(e))return true;return false;}List<Finding> scan(ScanFileInput file,Pattern p,String title,Severity sev,Category cat,String rec){List<Finding> out=new ArrayList<>();Matcher m=p.matcher(file.content());while(m.find())out.add(f(file,title,sev,cat,Confidence.HIGH,m.group(),rec));return out;}}
@Component class SecretRule extends BaseRule{public String id(){return"SEC-001";}public String name(){return"Secret detection";}public Category category(){return Category.SECRETS;}public Severity defaultSeverity(){return Severity.HIGH;}public boolean supports(ScanFileInput f){return true;}public List<Finding> analyze(ScanFileInput f){List<Finding> r=new ArrayList<>();r.addAll(scan(f,Pattern.compile("AKIA[0-9A-Z]{12,}|ASIA[0-9A-Z]{12,}|-----BEGIN PRIVATE KEY-----"),"Cloud credential or private key exposed",Severity.CRITICAL,Category.SECRETS,"Rotate exposed credentials and move secrets to a secret manager."));r.addAll(scan(f,Pattern.compile("(?i)(api[_-]?key|client_secret|jwt_secret|password|db_password|database_password)\\s*[:=]\\s*[\"']?[^\\s\"']{6,}"),"Hardcoded credential",Severity.HIGH,Category.SECRETS,"Use environment variables or managed secrets and add secret scanning to CI/CD."));return r;}}
@Component class CorsRule extends BaseRule{public String id(){return"API-001";}public String name(){return"Dangerous CORS";}public Category category(){return Category.API_SECURITY;}public Severity defaultSeverity(){return Severity.MEDIUM;}public boolean supports(ScanFileInput f){return true;}public List<Finding> analyze(ScanFileInput f){Severity s=f.content().toLowerCase().contains("credentials")?Severity.HIGH:Severity.MEDIUM;return scan(f,Pattern.compile("Access-Control-Allow-Origin:\\s*\\*|allowedOrigins\\(\\s*\"\\*\"|cors\\(\\s*\\{[^}]*origin\\s*:\\s*[\"']\\*[\"']|CORS\\([^)]*\\*"),"Wildcard CORS policy",s,Category.API_SECURITY,"Restrict CORS to trusted origins and never combine wildcard origins with credentials.");}}
@Component class CookieDebugRule extends BaseRule{public String id(){return"APP-001";}public String name(){return"Cookies and debug";}public Category category(){return Category.DATA_EXPOSURE;}public Severity defaultSeverity(){return Severity.MEDIUM;}public boolean supports(ScanFileInput f){return true;}public List<Finding> analyze(ScanFileInput f){List<Finding> r=scan(f,Pattern.compile("(?i)setcookie|Set-Cookie"),"Cookie may be missing HttpOnly/Secure/SameSite",Severity.MEDIUM,Category.DATA_EXPOSURE,"Set HttpOnly, Secure, and SameSite=Lax or Strict on session cookies.");r.addAll(scan(f,Pattern.compile("(?i)debug\\s*[:=]\\s*true|app\\.debug\\s*=\\s*True|stacktrace"),"Debug mode or stack traces enabled",Severity.MEDIUM,Category.DATA_EXPOSURE,"Disable debug mode in production and return safe errors."));return r;}}
@Component class InjectionRule extends BaseRule{public String id(){return"INJ-001";}public String name(){return"Injection patterns";}public Category category(){return Category.INPUT_VALIDATION;}public Severity defaultSeverity(){return Severity.HIGH;}public boolean supports(ScanFileInput f){return true;}public List<Finding> analyze(ScanFileInput f){List<Finding> r=scan(f,Pattern.compile("(?is)(SELECT|UPDATE|DELETE|INSERT)[^\\n;]*(\\+|`\\$\\{|f[\"'])|Statement\\s+\\w+\\s*=|createStatement\\("),"Possible SQL injection pattern",Severity.HIGH,Category.INPUT_VALIDATION,"Use prepared statements, ORM parameter binding, or safe query builders.");r.addAll(scan(f,Pattern.compile("Runtime\\.getRuntime\\(\\)\\.exec|child_process\\.exec|os\\.system|subprocess\\.[^(]+\\([^)]*shell\\s*=\\s*True"),"Command execution requires strict validation",Severity.HIGH,Category.INPUT_VALIDATION,"Avoid shell execution; use safe APIs and allowlisted arguments."));return r;}}
@Component class JwtAuthLogRule extends BaseRule{public String id(){return"AUTH-001";}public String name(){return"JWT/auth/logging";}public Category category(){return Category.AUTHENTICATION;}public Severity defaultSeverity(){return Severity.HIGH;}public boolean supports(ScanFileInput f){return true;}public List<Finding> analyze(ScanFileInput f){List<Finding> r=scan(f,Pattern.compile("alg\\s*[:=]\\s*[\"']none|verify\\s*[:=]\\s*false|JWT_SECRET\\s*[:=]\\s*[\"'][^\"']{1,15}[\"']"),"Weak JWT handling",Severity.HIGH,Category.AUTHENTICATION,"Use strong signing secrets, enforce verification, and rotate tokens.");r.addAll(scan(f,Pattern.compile("(?i)(/admin|/payments|/accounts|/internal|/delete|/export)"),"Sensitive endpoint should require authentication",Severity.MEDIUM,Category.AUTHORIZATION,"Apply authentication, authorization, and role checks to sensitive routes."));r.addAll(scan(f,Pattern.compile("(?i)(console\\.log|logger\\.(info|debug)|print)\\([^)]*(password|token|secret|authorization)"),"Sensitive data logged",Severity.MEDIUM,Category.LOGGING_MONITORING,"Redact secrets and authorization headers from logs."));r.addAll(scan(f,Pattern.compile("(?i)(/login|/auth|password-reset)"),"Authentication endpoint should include rate limiting",Severity.MEDIUM,Category.API_SECURITY,"Add rate limiting to authentication and recovery endpoints."));return r;}}
@Component class CloudDockerDependencyRule extends BaseRule{public String id(){return"CFG-001";}public String name(){return"Cloud Docker dependency";}public Category category(){return Category.CLOUD_CONFIGURATION;}public Severity defaultSeverity(){return Severity.HIGH;}public boolean supports(ScanFileInput f){return true;}public List<Finding> analyze(ScanFileInput f){List<Finding> r=new ArrayList<>();r.addAll(scan(f,Pattern.compile("\"Action\"\\s*:\\s*\"\\*\"|\"Resource\"\\s*:\\s*\"\\*\"|AdministratorAccess|iam:\\*|s3:\\*"),"Overly permissive IAM policy",Severity.HIGH,Category.CLOUD_CONFIGURATION,"Apply least privilege and scope actions/resources."));r.addAll(scan(f,Pattern.compile("public-read|block_public_acls\\s*=\\s*false|block_public_policy\\s*=\\s*false|ignore_public_acls\\s*=\\s*false|Principal\\s*[:=]\\s*\"\\*\""),"Public S3 access risk",Severity.HIGH,Category.CLOUD_CONFIGURATION,"Enable S3 Block Public Access and restrict bucket policies."));r.addAll(scan(f,Pattern.compile("FROM\\s+\\S+:latest|COPY\\s+\\.\\s+\\.|ADD\\s+https?://|ENV\\s+.*(SECRET|PASSWORD|TOKEN)|EXPOSE\\s+(22|3306|5432|6379)"),"Insecure Dockerfile pattern",Severity.LOW,Category.CONTAINER_SECURITY,"Pin image tags, use a non-root USER, and avoid baking secrets into images."));if(f.fileName().equalsIgnoreCase("Dockerfile")&&!f.content().contains("USER "))r.add(f(f,"Dockerfile missing non-root USER",Severity.MEDIUM,Category.CONTAINER_SECURITY,Confidence.HIGH,"Dockerfile","Run containers as a non-root user."));r.addAll(scan(f,Pattern.compile("curl\\s+[^|]+\\|\\s*(sh|bash)|postinstall.*(curl|wget|bash)"),"Suspicious dependency install script",Severity.HIGH,Category.DEPENDENCY,"Review install scripts and use dependency scanning."));return r;}}
